from pathlib import Path
import re
root=Path('.gsd/milestones/M001/slices')

def section(text, heading):
    # match ## heading until next ## or # at same/lower level
    pat=re.compile(rf'(^## {re.escape(heading)}\s*$)(.*?)(?=^## |^# |\Z)', re.M|re.S)
    m=pat.search(text)
    return (m.group(2).strip() if m else '')

def first_nonempty(lines):
    for l in lines:
        l=l.strip()
        if l and not l.startswith('---'):
            return l
    return ''

for sd in sorted(p for p in root.iterdir() if p.is_dir() and re.match(r'S\d+', p.name)):
    summ=sd/f'{sd.name}-SUMMARY.md'
    uat=sd/f'{sd.name}-UAT.md'
    print(f'## {sd.name}')
    if summ.exists():
        text=summ.read_text(encoding='utf-8')
        # title/one-liner: first heading after frontmatter, plus summary-like sections
        headings=re.findall(r'^#\s+(.+)$', text, re.M)
        print('SUMMARY_TITLE:', headings[0] if headings else '')
        for h in ['Verification','Operational Readiness','Known Limitations','Follow-ups','Requirements Validated','Requirements Advanced']:
            s=section(text,h)
            if s:
                one=' '.join(s.split())[:800]
                print(f'{h}: {one}')
    else:
        print('SUMMARY_MISSING')
    if uat.exists():
        text=uat.read_text(encoding='utf-8')
        headings=re.findall(r'^#\s+(.+)$', text, re.M)
        print('UAT_TITLE:', headings[0] if headings else '')
        for h in ['UAT Type','Acceptance Checks','Acceptance Steps','Expected Results','Expected Operational Signals','Not Proven By This UAT','Verification Evidence','Result']:
            s=section(text,h)
            if s:
                one=' '.join(s.split())[:800]
                print(f'UAT {h}: {one}')
    else:
        print('UAT_MISSING')
    print()

